const mkdirp = require('mkdirp');
const { promisify } = require('util');

const writeFileAsync = promisify(fs.writeFile);
const mkdirpAsync = promisify(mkdirp);

const createController = async (controllerName) => {
  const content = `class ${controllerName}Controller {
  // Implement REST API methods here
}

module.exports = new ${controllerName}Controller();`;

  // Write the controller file
  await writeFileAsync(`./controllers/${controllerName}Controller.js`, content);
};

const createProjectStructure = async (answers) => {
  // Create directories based on answers
  // ...

  if (answers.projectType === 'Server') {
    // Create a folder for controllers
    await mkdirpAsync('./controllers');

    // Iterate over the controllers provided and create them
    for (const controller of answers.controllers) {
      await createController(controller);
    }
  }
  // ...
};

module.exports = { createProjectStructure };
```

