const program = require('commander');
const { version } = require('../package.json');
const { createApiProject } = require('./utils');

program
  .version(version)
  .description("Generate a new Node.js REST API project")
  .command('create-api')
  .description("Create a REST API service with Node.js")
  .action(createApiProject);

program.parse(process.argv);
